options.getOption:
const frame = context.panel.data.series && context.panel.data.series[0];
if (!frame) {
  return { backgroundColor: 'transparent', title: { text: 'No data in range', left: 'center', top: 'center', textStyle: { color: '#888', fontSize: 14 } } };
}

const fieldVals = (name) => {
  const f = frame.fields.find((x) => x.name === name);
  if (!f) return [];
  return f.values.buffer || f.values;
};
const src = fieldVals('source');
const tgt = fieldVals('target');
const val = fieldVals('value');

// Node colors mirror the bar-chart palette used elsewhere in the stack.
const colors = {
  'Solar': '#F2CC0C',        // sources (left)
  'Battery out': '#56A64B',
  'Grid in': '#E02F44',
  'Home': '#3D71D9',         // uses (right)
  'Battery in': '#73BF69',
  'Grid out': '#B877D9',
};
// Light-colored boxes get dark text for contrast.
const darkLabel = { 'Solar': true, 'Battery in': true };
// The battery charge/discharge nodes must stay distinct (one is a source, one
// a target — merging them would collapse the two-column layout), but both show
// as just 'Battery'. disp() maps internal node id -> displayed label.
const displayName = { 'Battery out': 'Battery', 'Battery in': 'Battery', 'Home': 'Load' };
const disp = (n) => displayName[n] || n;
// Top-to-bottom order within each column. layoutIterations:0 below makes the
// sankey honour this order instead of auto-sorting to minimise crossings.
const order = ['Solar', 'Battery out', 'Grid in', 'Battery in', 'Home', 'Grid out'];

const present = new Set();
for (let i = 0; i < src.length; i++) { present.add(src[i]); present.add(tgt[i]); }

const nodes = order.filter((n) => present.has(n)).map((n) => ({
  name: n,
  itemStyle: { color: colors[n] || '#888', borderColor: 'transparent' },
  label: { color: darkLabel[n] ? '#1F1F1F' : '#FFFFFF' },
}));

const links = [];
for (let i = 0; i < src.length; i++) {
  links.push({ source: src[i], target: tgt[i], value: Number(val[i]) });
}

return {
  backgroundColor: 'transparent',
  tooltip: {
    trigger: 'item',
    formatter: (p) => {
      if (p.dataType === 'edge') {
        return disp(p.data.source) + ' → ' + disp(p.data.target) + '<br/><b>' + p.value.toFixed(2) + ' kWh</b>';
      }
      return '<b>' + disp(p.name) + '</b><br/>' + (p.value != null ? p.value.toFixed(2) + ' kWh' : '');
    },
  },
  series: [{
    type: 'sankey',
    left: 8,
    right: 8,
    top: 22,
    bottom: 14,
    nodeWidth: 96,
    nodeGap: 14,
    layoutIterations: 0,
    draggable: false,
    emphasis: { focus: 'adjacency' },
    label: {
      position: 'inside',
      formatter: (p) => '{a|' + disp(p.name) + '}\n{b|' + (p.value != null ? p.value.toFixed(1) + ' kWh' : '') + '}',
      rich: {
        a: { fontSize: 13, fontWeight: 'bold', lineHeight: 20 },
        b: { fontSize: 11, lineHeight: 16 },
      },
    },
    lineStyle: { color: 'gradient', opacity: 0.45, curveness: 0.5 },
    data: nodes,
    links: links,
  }],
};
